import React from "react";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import "../App.css";

const Home = () => {
  const navigate = useNavigate();

  return (
    <div className="background-gradient h-screen flex flex-col justify-center items-center text-center relative">

      {/* ✅ SVG ที่แยกชิ้นส่วนได้ */}
      <div className="lantern-container">
        <LanternSVG className="lantern-svg" />

        {/* ✅ ขยับเฉพาะโคมไฟแต่ละลูก */}
        <motion.div
          className="lantern lantern1"
          animate={{ rotate: [-5, 5, -5], y: [0, 10, 0] }}
          transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
        />

        <motion.div
          className="lantern lantern2"
          animate={{ rotate: [5, -5, 5], y: [5, 0, 5] }}
          transition={{ duration: 2.5, repeat: Infinity, ease: "easeInOut" }}
        />
      </div>


      {/* 📌 เนื้อหาหน้า Home */}
      <div className="home-container mt-24">
        <h1 className="text-5xl font-bold text-pink-600 mb-4 font-Phudu">
          Capturing | Booth
        </h1>
        <h4 className="text-lg text-gray-700 mb-6">
          Welcome to Capturing! Photobooth! Lumen & LifeVoyage.
        </h4>
        <img src="/photobooth1.png" alt="photobooth strip" className="photobooth-strip" />
        <button onClick={() => navigate("/welcome")} className="start-button">
          START
        </button>
        <footer className="mt-8 text-sm text-gray-600 text-center font-kanit">
          <p>Version 1.0.3</p>
        </footer>
      </div>
    </div>


  );
};

export default Home;
